#include <iostream>
#include <string>
#include <fstream>
using namespace std;

int searchByName(string names[], int count, string target) {
    for (int i = 0; i < count; i++) {
        if (names[i] == target)
            return i;
    }
    return -1;
}

void sortByPrice(string names[], double prices[], int quantities[], int count) {
    for (int i = 0; i < count - 1; i++) {
        for (int j = 0; j < count - i - 1; j++) {
            if (prices[j] > prices[j + 1]) {
                swap(names[j], names[j + 1]);
                swap(prices[j], prices[j + 1]);
                swap(quantities[j], quantities[j + 1]);
            }
        }
    }
}

